args.sparql:
SELECT ?character WHERE {
  ?show rdfs:label "The Expanse"@en .
  ?person rdfs:label "Cara Gee"@en .
  ?show p:P161 [
    ps:P161 ?person;
    pq:P4499 ?character
  ] .
}

SELECT ?characterName WHERE {
  wd:Q200080 p:P161 [
    ps:P161 wd:Q6838768 ;
    pq:P4499 ?characterName
  ] .
  FILTER(LANG(?characterName) = 'en')
}

